INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ba7f2252-38e3-4bae-8013-9bb17acfd03b',
  '00000000-0000-0000-0000-000000000001',
  $escape$c pointers - Raw vs. Dangling$escape$,
  $escape$Raw pointers in c are declared with the asterisk symbol (*) and can point to any memory location. However, they don't perform any memory management and must be manually managed. Dangling pointers occur when the memory pointed to is deallocated. To avoid memory leaks, use dynamic memory allocation functions like `malloc()` and `free()` carefully. The `NULL` macro can be used to initialize raw pointers.$escape$,
  $escape$int* p = malloc(sizeof(int));
* p = 10;
free(p); // Don't forget to free the memory!
p = NULL;$escape$,
  $escape$c$escape$,
