INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0495fe96-469d-4d42-b2f4-3a84c681531d',
  '00000000-0000-0000-0000-000000000001',
  $escape$C FFI & Interop — Calling C from Rust/Zig via C ABI$escape$,
  $escape$To call C functions from Rust or Zig, you need to use the C Foreign Function Interface (FFI). The Rust `libc` crate and Zig's `foreign` module provide the necessary bindings. However, you must ensure the C functions are compiled with the correct C ABI (Application Binary Interface). The C ABI dictates the calling convention, function signature, and data layout. When generating bindings, you need to specify the C ABI in the compiler flags, such as `-mabi=sysv` for the System V ABI. This ensures the generated code matches the C ABI and can be called from Rust or Zig.$escape$,
  $escape$/* rust */
cargo build -p libc

// main.rs
cargo run --example example

/* zig */
zig build-exe -f src/main.zig

// main.zig
cargo run --example example$escape$,
  $escape$c$escape$,
